import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { WCA_COUNTRIES_MAP, WCA_COUNTRIES, type WCACountry } from "@/data/wcaCountries";

export interface GlobePartner {
  id: string;
  company_name: string;
  city: string;
  country_code: string;
  country_name: string;
  email: string | null;
  partner_type: string | null;
  lat: number;
  lng: number;
}

export interface CountryWithPartners {
  code: string;
  name: string;
  count: number;
  lat: number;
  lng: number;
  region: WCACountry['region'];
}

const PRECOMPUTED_COUNTRIES_MAP: Record<string, CountryWithPartners> = {};
const PRECOMPUTED_COUNTRIES: CountryWithPartners[] = WCA_COUNTRIES.map(country => {
  const cwp: CountryWithPartners = {
    code: country.code, name: country.name, count: 0,
    lat: country.lat, lng: country.lng, region: country.region,
  };
  PRECOMPUTED_COUNTRIES_MAP[country.code] = cwp;
  return cwp;
});

export function usePartnersForGlobe() {
  return useQuery({
    queryKey: ["partners-globe"],
    queryFn: async () => {
      const { data: partners, error } = await supabase
        .from("partners")
        .select("id, company_name, city, country_code, country_name, email, partner_type")
        .eq("is_active", true)
        .order("company_name");
      if (error) throw error;
      const countryCounts: Record<string, number> = {};
      const globePartners: GlobePartner[] = (partners || []).map(p => {
        countryCounts[p.country_code] = (countryCounts[p.country_code] || 0) + 1;
        const country = PRECOMPUTED_COUNTRIES_MAP[p.country_code];
        return { ...p, lat: country?.lat || 0, lng: country?.lng || 0 };
      });
      const countriesWithPartners = PRECOMPUTED_COUNTRIES.map(c => ({ ...c, count: countryCounts[c.code] || 0 }));
      const countriesMap = countriesWithPartners.reduce((acc, c) => { acc[c.code] = c; return acc; }, {} as Record<string, CountryWithPartners>);
      return { partners: globePartners, countries: countriesWithPartners, countriesMap };
    },
    staleTime: 5_000,
    gcTime: 10 * 60 * 1000,
    refetchInterval: 8_000,
  });
}

export function usePartnersByCountryForGlobe(countryCode: string | null) {
  return useQuery({
    queryKey: ["partners-globe-country", countryCode],
    queryFn: async () => {
      if (!countryCode) return [];
      const { data, error } = await supabase
        .from("partners")
        .select("id, company_name, city, country_code, country_name, email, partner_type")
        .eq("is_active", true)
        .eq("country_code", countryCode)
        .order("company_name");
      if (error) throw error;
      const country = PRECOMPUTED_COUNTRIES_MAP[countryCode];
      return (data || []).map(p => ({ ...p, lat: country?.lat || 0, lng: country?.lng || 0 }));
    },
    enabled: !!countryCode,
    staleTime: 5_000,
    gcTime: 5 * 60 * 1000,
    refetchInterval: 8_000,
  });
}
